const item = $input.first().json;
const now = new Date();
const iso = now.toISOString();
const stamp = iso.replace(/[:.]/g, '-');
const date = iso.slice(0, 10);
let content = item.choices?.[0]?.message?.content;
let verdict = 'WARN';
if (!content) {
  content = `# Qwen Project Worker Report\n\n## Verdict\nFAIL: Qwen did not return a normal chat completion.\n\n## Raw Error\n\n\`\`\`json\n${JSON.stringify(item, null, 2).slice(0, 6000)}\n\`\`\``;
} else if (/^## Verdict\s*\n\s*PASS/im.test(content) || /\bPASS\b/.test(content.slice(0, 250))) {
  verdict = 'PASS';
}
const report = `<!-- generated by n8n workflow: Qwen Project Worker - 30 Minute Repo Review -->\n<!-- generated_at: ${iso} -->\n\n${content.trim()}\n`;
const reportPath = `reports/qwen-worker/${date}/${stamp}.md`;
return [{ json: { report, report_base64: Buffer.from(report, 'utf8').toString('base64'), report_path: reportPath, generated_at: iso, verdict } }];
